                    hasPingedVcServer = true;
                    vcPingsCache[svalue] = true;
                    var request1 = new XMLHttpRequest();
                    request1.open("GET", pingUrl);
                    // Conditionally set the header
                    if (typeof liuIdOrNull !== 'undefined' && liuIdOrNull) {
